import{_ as n,C as r,o as t,c as s,a2 as a,b as l,w as i,a as c,E as h,a3 as d}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"ForgeCode — Multi-Agent Loop Orchestration","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/forgecode/agentic-loop.md","filePath":"research/agents/forgecode/agentic-loop.md"}'),g={name:"research/agents/forgecode/agentic-loop.md"};function p(u,e,m,f,b,k){const o=r("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="forgecode-—-multi-agent-loop-orchestration" tabindex="-1">ForgeCode — Multi-Agent Loop Orchestration <a class="header-anchor" href="#forgecode-—-multi-agent-loop-orchestration" aria-label="Permalink to &quot;ForgeCode — Multi-Agent Loop Orchestration&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ForgeCode does not use a single agentic loop. It orchestrates across three sub-agents (Forge, Muse, Sage), each with different access levels and thinking budgets, managed by a runtime layer (ForgeCode Services) that enforces planning, controls reasoning budgets, and corrects tool calls.</p><h2 id="the-orchestration-flow" tabindex="-1">The Orchestration Flow <a class="header-anchor" href="#the-orchestration-flow" aria-label="Permalink to &quot;The Orchestration Flow&quot;">​</a></h2><h3 id="typical-task-lifecycle" tabindex="-1">Typical Task Lifecycle <a class="header-anchor" href="#typical-task-lifecycle" aria-label="Permalink to &quot;Typical Task Lifecycle&quot;">​</a></h3>',5)),(t(),l(d,null,{default:i(()=>[h(o,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%20prompt%20(via%20%3A%20in%20ZSH)%22%5D%20--%3E%20B%0A%20%20%20%20B%5B%221.%20Entry-Point%20Discovery%3Cbr%2F%3ESemantic%20search%20identifies%20most%20relevant%20files%3Cbr%2F%3E(ForgeCode%20Services%20%E2%80%94%20before%20any%20agent%20runs)%22%5D%20--%3E%20C%0A%20%20%20%20C%5B%222.%20Skill%20Routing%3Cbr%2F%3ETask%20profile%20%E2%86%92%20load%20right%20skill%3Cbr%2F%3E(ForgeCode%20Services)%22%5D%20--%3E%20D%0A%20%20%20%20D%5B%223.%20Agent%20Loop%3Cbr%2F%3EReason%20%C2%B7%20Call%20tools%20%C2%B7%20Update%20todo%20state%20%C2%B7%20Delegate%20to%20SAGE%3Cbr%2F%3E(MUSE%20or%20FORGE)%22%5D%20--%3E%20E%0A%20%20%20%20E%5B%22Tool-Call%20Correction%3Cbr%2F%3EIntercept%20%26amp%3B%20fix%3Cbr%2F%3E(ForgeCode%20Services%20%E2%80%94%20before%20every%20dispatch)%22%5D%20--%3E%20F%0A%20%20%20%20F%5B%22Tool%20Execution%3Cbr%2F%3Eshell%2C%20edit%2C%20search%22%5D%20--%3E%20G%7BTask%20done%3F%7D%0A%20%20%20%20G%20--%20no%20--%3E%20D%0A%20%20%20%20G%20--%20yes%20--%3E%20H%0A%20%20%20%20H%5B%224.%20Verification%20Enforcement%3Cbr%2F%3EInjects%20reviewer%20mode%20if%20verification%20skill%20not%20called%3Cbr%2F%3E(ForgeCode%20Services%20%E2%80%94%20before%20task%20completion)%22%5D%20--%3E%20I%5B%22Task%20Complete%22%5D%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="phase-1-pre-agent-setup" tabindex="-1">Phase 1: Pre-Agent Setup <a class="header-anchor" href="#phase-1-pre-agent-setup" aria-label="Permalink to &quot;Phase 1: Pre-Agent Setup&quot;">​</a></h2><p>Before any agent starts reasoning, ForgeCode Services performs two preparatory steps:</p><h3 id="semantic-entry-point-discovery" tabindex="-1">Semantic Entry-Point Discovery <a class="header-anchor" href="#semantic-entry-point-discovery" aria-label="Permalink to &quot;Semantic Entry-Point Discovery&quot;">​</a></h3><p>The context engine runs a lightweight semantic pass over the indexed codebase to identify the most likely starting files and functions for the given task. This addresses a critical failure mode identified during TermBench evaluation: agents that explore randomly waste their time budget.</p><p><strong>Without entry-point discovery</strong>: Agent reads <code>ls</code>, explores directory tree, reads unrelated files, eventually finds the right module after burning 30% of its time budget.</p><p><strong>With entry-point discovery</strong>: Agent starts in the right file/function immediately. More context then helps it reason more deeply from the correct starting point.</p><h3 id="dynamic-skill-loading" tabindex="-1">Dynamic Skill Loading <a class="header-anchor" href="#dynamic-skill-loading" aria-label="Permalink to &quot;Dynamic Skill Loading&quot;">​</a></h3><p>The skill engine matches the task profile against available skills and loads only the relevant ones. Each skill is a specialized instruction set — it might include:</p><ul><li>Domain-specific tool-calling patterns</li><li>Preferred sequences of operations</li><li>Quality criteria for the task type</li><li>Known pitfalls and how to avoid them</li></ul><p>Skills that aren&#39;t relevant stay unloaded, keeping the system prompt lean.</p><h2 id="phase-2-the-agent-loop" tabindex="-1">Phase 2: The Agent Loop <a class="header-anchor" href="#phase-2-the-agent-loop" aria-label="Permalink to &quot;Phase 2: The Agent Loop&quot;">​</a></h2><h3 id="progressive-thinking-policy" tabindex="-1">Progressive Thinking Policy <a class="header-anchor" href="#progressive-thinking-policy" aria-label="Permalink to &quot;Progressive Thinking Policy&quot;">​</a></h3><p>The reasoning budget changes as the agent progresses through a task:</p><p><strong>Messages 1–10 (Planning Phase)</strong>:</p><ul><li>Very high thinking budget</li><li>This is where the agent forms its plan, identifies problem structure, and selects its approach</li><li>Getting the plan right is worth the additional latency</li><li>The <code>todo_write</code> tool must be called to create task items for multi-step work</li></ul><p><strong>Messages 11+ (Execution Phase)</strong>:</p><ul><li>Low thinking budget by default</li><li>The plan is set; the agent should act, not re-deliberate</li><li>Sub-agents handle parallelizable work (file reads, pattern searches)</li><li>Each completed sub-task is marked done via <code>todo_write</code></li></ul><p><strong>Verification Checkpoint</strong>:</p><ul><li>When the verification skill is invoked, thinking budget switches back to high</li><li>The agent shifts from builder mode to reviewer mode</li></ul><h3 id="the-inner-loop" tabindex="-1">The Inner Loop <a class="header-anchor" href="#the-inner-loop" aria-label="Permalink to &quot;The Inner Loop&quot;">​</a></h3><p>Each turn within an agent follows this cycle:</p><ol><li><strong>Reason</strong>: The model considers the current state, remaining tasks, and available tools</li><li><strong>Select tool</strong>: Choose the appropriate tool call (edit, shell, search, etc.)</li><li><strong>Tool-call correction</strong>: ForgeCode Services intercepts the call, validates arguments, and auto-corrects if needed</li><li><strong>Execute</strong>: The tool runs and returns results</li><li><strong>Update state</strong>: If applicable, <code>todo_write</code> is called to update task progress</li><li><strong>Check completion</strong>: Is the task done? If not, loop back to step 1</li></ol><h3 id="sage-delegation" tabindex="-1">Sage Delegation <a class="header-anchor" href="#sage-delegation" aria-label="Permalink to &quot;Sage Delegation&quot;">​</a></h3><p>When Forge or Muse needs deeper codebase understanding, they delegate to Sage:</p><ul><li>Sage operates in read-only mode with focused context</li><li>It traces functionality across files, maps dependencies, and analyzes architecture</li><li>Only the relevant findings are returned to the calling agent — not the full investigation context</li><li>This prevents context bloat in the main agent&#39;s window</li></ul><h3 id="sub-agent-parallelization" tabindex="-1">Sub-Agent Parallelization <a class="header-anchor" href="#sub-agent-parallelization" aria-label="Permalink to &quot;Sub-Agent Parallelization&quot;">​</a></h3><p>For low-complexity, parallelizable work, ForgeCode spawns sub-agents:</p><ul><li>File reads across multiple locations</li><li>Pattern searches in different directories</li><li>Routine edits that don&#39;t depend on each other</li></ul><p>Sub-agents run with minimal thinking budget. The main agent coordinates results and handles decisions that require deeper reasoning.</p><h2 id="phase-3-verification-enforcement" tabindex="-1">Phase 3: Verification Enforcement <a class="header-anchor" href="#phase-3-verification-enforcement" aria-label="Permalink to &quot;Phase 3: Verification Enforcement&quot;">​</a></h2><p>This is ForgeCode&#39;s most distinctive loop feature. Before a task is marked complete:</p><ol><li><strong>Check</strong>: Has the agent called the verification skill?</li><li><strong>If no</strong>: The runtime injects a reminder and requires a verification pass. No opt-out.</li><li><strong>If yes</strong>: The verification skill asks a different question from building: &quot;What evidence proves this objective is actually complete?&quot;</li></ol><p>The verification pass generates a checklist:</p><ul><li>What was requested</li><li>What was actually done</li><li>What evidence exists that it worked</li><li>What is still missing</li></ul><p>If gaps are found, the agent generates follow-up tasks and completes them before exiting.</p><p><strong>Why enforcement matters</strong>: Normal prompting (&quot;please verify your work&quot;) does not reliably produce this behavior. Models under pressure take the path of least resistance — they skip verification when it&#39;s optional. Programmatic enforcement was the key insight that drove a significant score improvement on TermBench.</p><h2 id="non-interactive-mode" tabindex="-1">Non-Interactive Mode <a class="header-anchor" href="#non-interactive-mode" aria-label="Permalink to &quot;Non-Interactive Mode&quot;">​</a></h2><p>For benchmark evaluation and CI/CD usage, ForgeCode has a strict Non-Interactive Mode:</p><ul><li>System prompt rewritten to prohibit clarification requests and conversational branching</li><li>The agent assumes reasonable defaults and proceeds autonomously</li><li>Completion logic tightened so the agent commits rather than hedging</li><li>No user to answer questions — every turn asking is a turn not solving</li></ul><p>This mode was essential for TermBench: the interactive-first agent scored ~25%. Non-Interactive Mode + tool fixes brought it to ~38% before other improvements.</p><h2 id="the-plan-and-act-pattern" tabindex="-1">The Plan-and-Act Pattern <a class="header-anchor" href="#the-plan-and-act-pattern" aria-label="Permalink to &quot;The Plan-and-Act Pattern&quot;">​</a></h2><p>The recommended user workflow mirrors the internal architecture:</p><ol><li><p><strong><code>:muse</code> — Plan</strong>: Switch to Muse agent. Ask it to analyze the task and produce a detailed implementation plan. Muse operates read-only, so it can think freely without side effects.</p></li><li><p><strong>Review</strong>: The user reviews Muse&#39;s plan, asks for refinements.</p></li><li><p><strong><code>:forge</code> — Execute</strong>: Switch to Forge agent. Reference the plan and begin implementation. Forge has full read+write access.</p></li><li><p><strong>Iterate</strong>: If complex decisions arise during implementation, switch back to Muse for analysis, then return to Forge.</p></li></ol><p>Context is preserved across agent switches, but each agent&#39;s internal working context remains bounded.</p><h2 id="failure-budget-management" tabindex="-1">Failure Budget Management <a class="header-anchor" href="#failure-budget-management" aria-label="Permalink to &quot;Failure Budget Management&quot;">​</a></h2><p>TermBench imposes strict wall-clock time limits. ForgeCode manages failure budgets:</p><ul><li><strong><code>max_tool_failure_per_turn</code></strong>: Limits how many times a tool can fail before forcing completion (prevents infinite retry loops)</li><li><strong><code>max_requests_per_turn</code></strong>: Caps total requests per turn to control API costs</li><li><strong>Tool timeout</strong>: <code>FORGE_TOOL_TIMEOUT</code> (default 300s) kills hung tool executions</li></ul><h2 id="session-continuity" tabindex="-1">Session Continuity <a class="header-anchor" href="#session-continuity" aria-label="Permalink to &quot;Session Continuity&quot;">​</a></h2><ul><li>Conversations persist across prompts within a ZSH session</li><li><code>:new</code> starts a fresh conversation (clears history, keeps agent selection)</li><li><code>:conversation</code> switches between saved conversations</li><li><code>:retry</code> resends the last prompt after a cancel or timeout</li><li>Model and agent switches preserve conversation context</li></ul>',49))])}const w=n(g,[["render",p]]);export{y as __pageData,w as default};
